UPDATE public.questions SET
  stimulus_text = 'The use of commas in a series of three or more items is a common convention in Standard English.  However, there are some cases where the comma before the conjunction "and" in a series is optional.  The rule of thumb is that the comma is needed if omitting it would cause confusion or ambiguity.  For example, in the sentence "The guests ate the main course, dessert, and coffee", the comma is not necessary because there is no risk of ambiguity without it. However, in the sentence "The guests ate the main course, dessert, and coffee, which was served in a fancy teacup", the comma is necessary to prevent the reader from misinterpreting "and coffee, which" as a phrase modifying "dessert."  The comma is also necessary when the final item in the series is a long phrase or a clause.  For example, in the sentence "The guests ate the main course, dessert, and a cup of coffee that was brewed especially for the occasion", the comma before "and" is needed because the final item in the series is a long phrase.',
  question_text = 'Which of the following sentences correctly uses a comma before the conjunction "and" in a series?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"The guests ate the main course, dessert, and the coffee was served with a dollop of whipped cream.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"The guests ate the main course, dessert, and a special, extra-large cookie that was baked just for them.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"The guests ate the main course, dessert, and a glass of wine, which was chilled to perfection.","is_correct":true,"explanation":"Choice C matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"The guests ate the main course, dessert, and coffee that was brewed with locally roasted beans.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'C',
  explanation = 'The final item in the series is a clause, "which was chilled to perfection.", so the comma is needed to prevent the reader from misinterpreting "and a glass of wine, which" as a phrase modifying "dessert." The other choices do not have this issue because the final item in the series is not a long phrase or clause. The passage states that "The use of commas in a series of three or more items is a common convention in Standard English. However, there are some…", which is the textual anchor for eliminating weaker choices. Choice C is correct because it aligns with that evidence: The guests ate the main course, dessert, and a glass of wine, which was chilled to perfection.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"BOU","domain_id":"conventions","opensat_index":1173,"opensat_domain":"Standard English Conventions","opensat_raw_id":"random_id_a1","opensat_difficulty":"Hard","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.887Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
  updated_at = now()
